import { beforeAll, describe, expect, it } from 'vitest';
import { dirname, join, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';
import { mkdir, writeFile } from 'node:fs/promises';

import { ensureFaceJpeg } from './helpers/deblur-fixtures';
import { chromaticBuleSieve } from '../src/chromatic-bule-sieve';
import { bettiSignature, isClosureAdmissible } from '../src/betti-signature';
import { crossModalSigmaScore } from '../src/cross-modal-moonshine';
import { forkRaceFoldDeblur } from '../src/forkraceFoldDeblur';
import { encodeRecoveredAsPNG, deblurAnyImage } from '../src/deblur-any-image';
import { TOWER_CEILINGS } from '../src/spectral-noise-monitor';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);
const REPO_ROOT = resolve(__dirname, '../../../..');
const SCRATCH = join(REPO_ROOT, '.qa-artifacts/scratch');

describe('all sieves cooperate on BoofCV face', () => {
  beforeAll(async () => {
    await ensureFaceJpeg();
  });

  it('runs Chromatic + Betti + Moonshine + Buleyean ensemble end-to-end', async () => {
    await mkdir(SCRATCH, { recursive: true });
    const inputPath = join(SCRATCH, 'kodim17-face-gaussian-full.jpg');

    // ----- Stage 1: Decode the input (via deblurAnyImage's internal decoder
    // by calling it once with a tiny σ — this gives us a Float32 RGB plane). -----
    const decoded = await deblurAnyImage(inputPath, {
      sigma: 0.5,
      channelMode: 'rgb',
      // psfSize must be small for the small assumed σ.
    });
    const W = decoded.width;
    const H = decoded.height;
    const rgb = decoded.recovered; // length W*H*3

    // ----- Stage 2: Chromatic Bule Sieve -----
    const chroma = await chromaticBuleSieve({
      data: rgb, width: W, height: H,
      options: { sigma: 1.0 },
    });

    // ----- Stage 3: Betti signature on the chroma-recovered luminance -----
    const lumi = new Float32Array(W * H);
    for (let i = 0; i < W * H; i++) {
      lumi[i] = 0.2126 * chroma.recovered[i * 3]
              + 0.7152 * chroma.recovered[i * 3 + 1]
              + 0.0722 * chroma.recovered[i * 3 + 2];
    }
    const betti = bettiSignature({ plane: lumi, width: W, height: H });
    const closureOk = isClosureAdmissible(betti, TOWER_CEILINGS.decagon);

    // ----- Stage 4: Cross-Modal Moonshine on synthetic audio -----
    // Visual sequence: per-row mean luminance.
    const visual = new Float32Array(H);
    for (let y = 0; y < H; y++) {
      let s = 0;
      for (let x = 0; x < W; x++) s += lumi[y * W + x];
      visual[y] = s / W;
    }
    // Audio sequence: ramp + sinusoid that approximates "talking" cadence.
    const audio = new Float32Array(H);
    for (let y = 0; y < H; y++) {
      audio[y] = 0.5 + 0.4 * Math.sin(2 * Math.PI * y / 16);
    }
    const moonshine = crossModalSigmaScore({
      visual, audio,
      baseSigma: 2.0,
      adjustmentStrength: 0.5,
    });

    // ----- Stage 5: Buleyean ensemble with bettiSieve + rejectionWeights -----
    const ensemble = await forkRaceFoldDeblur({
      input: { data: rgb, width: W, height: H, channels: 3 },
      configs: [
        { label: 'wiener-1.5',  options: { sigma: 1.5, channelMode: 'luminance' } },
        { label: 'wiener-2.5',  options: { sigma: 2.5, channelMode: 'luminance' } },
        { label: 'wiener-3.5',  options: { sigma: 3.5, channelMode: 'luminance' } },
        { label: 'rl-2.0',       options: { sigma: 2.0, method: 'richardson-lucy', iterations: 12, channelMode: 'luminance' } },
      ],
      // Real photos have far more topological complexity than synthetic
      // fixtures. Decagon (10) is the Pleromatic-closure ceiling for clean
      // synthetic substrates; on natural images we use Trihexenneon (54),
      // the sustained-pressure ceiling, so honest content isn't rejected.
      bettiSieve: { ceiling: TOWER_CEILINGS.trihexenneon },
      rejectionWeights: { alpha: 0.5 },
    });

    // ----- Stage 6: Save the final composed PNG. -----
    const outPath = join(SCRATCH, 'kodim17-face-all-sieves.png');
    await writeFile(outPath, await encodeRecoveredAsPNG({
      recovered: ensemble.recovered,
      width: ensemble.width,
      height: ensemble.height,
      channels: ensemble.channels,
      // Stub the rest of DeblurAnyImageResult.
      selectedSigma: 0,
      noiseFloorUsed: 0,
      methodUsed: 'wiener',
      bilateralApplied: false,
      perChannel: [],
      analysis: undefined as never,
    }));

    // ----- Stage 7: Diagnostic trace. -----
    /* eslint-disable no-console */
    console.log(`\n[all-sieves demo on ${W}x${H} BoofCV face]`);
    console.log(`  Chromatic Bule:`);
    console.log(`    σ_C=${chroma.channelSigmas.c.toFixed(3)} σ_M=${chroma.channelSigmas.m.toFixed(3)} ` +
                `σ_Y=${chroma.channelSigmas.y.toFixed(3)} σ_K=${chroma.channelSigmas.k.toFixed(3)}`);
    console.log(`    cells=${chroma.cells.length}`);
    console.log(`  Betti: β₀=${betti.beta0} β₁=${betti.beta1} β₂=${betti.beta2} ` +
                `total=${betti.total} closure_admissible=${closureOk}`);
    console.log(`  Cross-Modal Moonshine:`);
    console.log(`    meanAgreement=${moonshine.meanAgreement.toFixed(3)} ` +
                `heartbeat={waste:${moonshine.heartbeat.waste}, opp:${moonshine.heartbeat.opportunity}, div:${moonshine.heartbeat.diversity}}`);
    console.log(`  Buleyean Ensemble:`);
    console.log(`    survivors=${ensemble.fold.survivors}/${ensemble.fold.rounds} ` +
                `totalWeight=${ensemble.fold.totalWeight}`);
    for (const c of ensemble.candidates) {
      const flag = c.rejectedByCeiling ? '[CEIL]' : (c.rejectedByBettiClosure ? '[BETTI]' : '');
      console.log(`    [rank=${c.rank} w=${c.buleyWeight}] ${c.label.padEnd(12)} σ=${c.selectedSigma.toFixed(3)} ${flag}`);
    }
    console.log(`  → ${outPath}\n`);

    // ----- Assertions: -----
    expect(chroma.recovered.length).toBe(W * H * 3);
    expect(chroma.cells.length).toBe(9);
    expect(Number.isFinite(betti.total)).toBe(true);
    expect(moonshine.sigmaPerFrame.length).toBe(H);
    expect(ensemble.fold.survivors).toBeGreaterThan(0);
    expect(ensemble.recovered.length).toBe(W * H * 3);
  }, 600_000);
});
